def validate_monto(m):
    if m is None:
        return "review"
    if m < 0:
        return "reject"
    if m == 0:
        return "accept"  # 0 puede ser válido; no colapsar con if not m
    return "accept"

for x in (None, -1, 0, 10):
    print(x, validate_monto(x))

