def bad(s):
    label = "reject"
    if s >= 50:
        label = "review"
    if s >= 80:
        label = "accept"
    # bug típico: ifs independientes mal ordenados en otras versiones
    return label

def good(s):
    if s >= 80:
        return "accept"
    elif s >= 50:
        return "review"
    else:
        return "reject"

for s in (95, 60, 10):
    print(s, "bad", bad(s), "good", good(s))

def band(n):
    if n > 100:
        return "alto"
    elif n > 50:
        return "medio"
    elif n > 0:
        return "bajo"
    else:
        return "nulo"

for n in (150, 75, 10, 0, -1):
    print(n, band(n))

def validate_edad(edad):
    if edad is None:
        return {"code": "MISSING", "status": "review"}
    if not isinstance(edad, int):
        return {"code": "BAD_TYPE", "status": "reject"}
    if edad < 0 or edad > 120:
        return {"code": "OUT_OF_RANGE", "status": "reject"}
    if edad < 18:
        return {"code": "NEEDS_REVIEW", "status": "review"}
    return {"code": "OK", "status": "accept"}

for e in (None, "18", -1, 15, 30):
    print(e, validate_edad(e))

def validate_monto_nested(m):
    # guards lineales (misma semántica que pirámide anidada)
    if m is None:
        return "review"
    if not isinstance(m, (int, float)):
        return "reject"
    if m < 0:
        return "reject"
    if m > 1_000_000:
        return "review"
    return "accept"

for m in (None, "x", -5, 10, 2_000_000):
    print(m, validate_monto_nested(m))

