TIPOS = {"DNI", "CE", "PAS"}
LENS = {"DNI": 8, "CE": 9, "PAS": 9}

def validar_doc(tipo, numero):
    if tipo is None or numero is None:
        return {"status": "review", "reason": "missing"}
    if tipo not in TIPOS:
        return {"status": "reject", "reason": "tipo"}
    if len(str(numero)) != LENS[tipo]:
        return {"status": "reject", "reason": "longitud"}
    return {"status": "accept", "reason": "ok"}

print(validar_doc("DNI", "12345678"))
print(validar_doc("DNI", "123"))
print(validar_doc("RUC", "12345678901"))

